"use strict";(self["webpackChunkbriefedition"]=self["webpackChunkbriefedition"]||[]).push([[818],{4818:function(e,n,i){i.r(n),i.d(n,{default:function(){return o}});var r=i(6768);const h={class:"about"};function s(e,n){return(0,r.uX)(),(0,r.CE)("div",h,[...n[0]||(n[0]=[(0,r.Lk)("div",{class:"row justify-content-center"},[(0,r.Lk)("div",{class:"col-9"},[(0,r.Lk)("h1",null,"Über diese Edition"),(0,r.Lk)("h3",null,"Sophie von La Roche"),(0,r.Lk)("p",null,' Sophie von La Roche (1730–1807) zählt zu den bedeutendsten deutschsprachigen Autorinnen der Empfindsamkeit und gilt als erste Schriftstellerin Deutschlands, die Geld mit dem Schreiben verdiente. Ihr 1771 veröffentlichter Roman „Die Geschichte des Fräuleins von Sternheim“ machte sie zur wohl bekanntesten Schriftstellerin Deutschlands in der zweiten Hälfte des 18. Jahrhunderts. Mit ihren Briefromanen sowie ihrer Monatszeitschrift "Pomona" widmete sie sich vor allem der Bildung und Erziehung von Frauen und Mädchen. Außerdem führte sie jahrelang einen literarischen Salon in Koblenz-Ehrenbreitstein und verfügte über ein ausgeprägtes Briefnetzwerk. In ihren Briefen verknüpft Sophie von La Roche rapide unterschiedlichste Themen in einer sprunghaften Gedankenführung. Zur Zeit der Briefe an Johann Isaak von Gerning lebte Sophie von La Roche in der Domstraße in Offenbach. Zu ihren späten Werken aus dieser Zeit zählen die zeitgeschichtlichen Romane „Schönes Bild der Resignation“, „Erscheinungen am See Oneida“, „Mein Schreibetisch“ und „Reise von Offenbach nach Weimar und Schönebeck im Jahr 1799“. '),(0,r.Lk)("h3",null,"Johann Isaak von Gerning"),(0,r.Lk)("p",null," Johann Isaak von Gerning (1767–1837) war Dichter und naturwissenschaftlich sowie künstlerisch interessierter Sammler. Die von seinem Vater Johann Christian Gerning begonnene und von ihm weitergeführte Sammlung bildet heute die Grundlage einiger Ausstellungen des Museums Wiesbaden. Johann Isaak von Gerning schrieb eigene Lyrik, übersetzte aber auch Gedichte des von ihm bewunderten römischen Dichters Ovid ins Deutsche. Außerdem veröffentlichte er Reisetagebücher über seine Österreich- und Italienreisen. Besonders verbunden fühlte er sich mit dem Taunus. Er lebte viele Jahre in seinem „Taunium“, einem Landhaus in Kronberg, und widmete dem Taunus Gedichte und andere Schriften. Daneben unterhielt er auch eine Wohnung in Frankfurt, von der aus er Sophie von La Roche oft in Offenbach besuchte. "),(0,r.Lk)("h3",null,"Die Briefe"),(0,r.Lk)("p",null," Thematisch erstrecken sich die Briefe Sophie von La Roches an Johann Isaak von Gerning über Bekanntschaften und Freundschaften, Privatangelegenheiten, Politik, Literatur, Kunst, Philosophie und das eigene literarische Schaffen. Dabei werden Meinungen zu Büchern, Lyrik, Essays oder Kunstwerken zwischen Gerning und La Roche ausgetauscht. Oft sendet La Roche ein ausgeliehenes Buch an Gerning zurück, empfiehlt ihm verschiedene Literatur oder bittet ihn um die Besorgung von Büchern. Auch der Inhalt eigener Werke ist in Sophie von La Roches Briefen Thema. Es werden z. B. Gedankengänge erklärt, die Einfluss auf ihre Werke genommen haben, oder Einblicke in den Schaffensprozess gewährt. Außerdem sind politische Ereignisse, wie Schlachten gegen die französische Armee, oder das Verhalten verschiedener Politiker oder Angehöriger europäischer Adelshäuser Thema der Briefe. Daneben werden Grüße an Freunde und Bekannte ausgesprochen oder Geschehnisse von Besuchen anderer Personen wiedergegeben. So geht es z.B. immer wieder um Johann Wolfgang von Goethe, Christoph Martin Wieland und Johann Gottfried Herder, zu denen Johann Isaak von Gerning zu dieser Zeit in Weimar Kontakt hatte. Auch Sophie von La Roches Enkel, vor allem Sophie Brentano, erscheinen in den Briefen. Sophie von La Roche spricht den 37 Jahre jüngeren Johann Isaak von Gerning in ihren Briefen meist mit „theurer Neffe“ an und bezeichnte sich selbst als „alte Tante“ oder „Tante La Roche“. In ihren Briefen gibt sie Gerning immer wieder Ratschläge zu verschiedenen Themen. Dabei handelt es sich vor allem um private Angelegenheiten, wie z.B. Gernings Gefühle gegenüber einer Frau oder seine Finanzen. ")])],-1)])])}var t=i(1241);const a={},d=(0,t.A)(a,[["render",s]]);var o=d}}]);
